import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useState } from 'react';
import { Alert, Image, Modal, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import { formatCurrency, WATER_PRODUCT } from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { createOrder, fetchCustomerOrders, fetchInventorySummary, OrderRecord, submitReview } from '../services/firebaseService';
import waterCanImage from '../assets/20-l-water-can1.jpg';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerHome'>;

const CustomerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [liveStock, setLiveStock] = useState(WATER_PRODUCT.availableStock);
  const [selectedRating, setSelectedRating] = useState(0);
  const [submittedRating, setSubmittedRating] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [ordering, setOrdering] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState<{ orderId: string; orderNumber?: number } | null>(null);

  useFocusEffect(
    useCallback(() => {
      let active = true;
      const load = async () => {
        if (!profile?.uid) { setOrders([]); return; }
        const [data, inv] = await Promise.all([
          fetchCustomerOrders(profile.uid).catch(() => []),
          fetchInventorySummary().catch(() => null)
        ]);
        if (!active) return;
        setOrders(data);
        if (inv) setLiveStock(Math.max(0, (inv.openingStock ?? 0) + (inv.restockedCans ?? 0) - (inv.soldCans ?? 0)));
      };
      load();
      return () => { active = false; };
    }, [profile?.uid])
  );

  const handleQuickOrder = async () => {
    if (!profile) return;
    if (!profile.address?.trim()) {
      Alert.alert('Address missing', 'Please add your delivery address in Profile first.', [
        { text: 'Go to Profile', onPress: () => navigation.navigate('Profile') },
        { text: 'Cancel', style: 'cancel' }
      ]);
      return;
    }
    setOrdering(true);
    try {
      const deliveryCharge = 0;
      const totalAmount = quantity * WATER_PRODUCT.pricePerCan;
      const result = await createOrder({
        customerId: profile.uid,
        customerName: profile.name,
        phone: profile.phone,
        address: profile.address.trim(),
        productName: WATER_PRODUCT.name,
        quantity,
        pricePerCan: WATER_PRODUCT.pricePerCan,
        deliveryCharge,
        totalAmount,
        availableStock: liveStock,
        note: '',
        paymentMethod: 'Cash on Delivery',
        paymentStatus: 'unpaid',
        paidAmount: 0,
        deliverySlot: 'Morning',
        expectedDeliveryTime: '7:00 AM - 10:00 AM',
        subscription: false
      });
      setOrders((prev) => [result as any, ...prev]);
      setOrderSuccess({ orderId: result.id!, orderNumber: result.orderNumber });
    } catch (e: any) {
      Alert.alert('Order failed', e.message || 'Could not place order. Try again.');
    } finally {
      setOrdering(false);
    }
  };

  const handleSubmitReview = async (rating: number) => {
    if (!profile?.uid || submitting) return;
    setSelectedRating(rating);
    setSubmitting(true);
    try {
      await submitReview(profile.uid, profile.name, rating);
      setSubmittedRating(rating);
      Alert.alert('Thank you!', `You rated us ${rating} star${rating > 1 ? 's' : ''}. We appreciate your feedback.`);
    } catch {
      Alert.alert('Error', 'Could not save your rating. Try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <Modal transparent visible={!!orderSuccess} animationType="fade" onRequestClose={() => setOrderSuccess(null)}>
        <View style={styles.successBackdrop}>
          <View style={styles.successCard}>
            <View style={styles.successIconCircle}>
              <AppIcon name="checkmark" size={36} color="#fff" />
            </View>
            <Text style={styles.successTitle}>Order Placed!</Text>
            <Text style={styles.successSub}>Order #{orderSuccess?.orderNumber} is confirmed.{`\n`}We'll deliver your water can soon.</Text>
            <Pressable style={styles.successBtn} onPress={() => setOrderSuccess(null)}>
              <Text style={styles.successBtnText}>Back to Home</Text>
            </Pressable>
            <Pressable style={styles.successSecondaryBtn} onPress={() => { setOrderSuccess(null); navigation.navigate('CustomerOrders'); }}>
              <Text style={styles.successSecondaryBtnText}>View My Orders</Text>
            </Pressable>
          </View>
        </View>
      </Modal>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>

        {/* Top bar */}
        <View style={styles.topBar}>
          <View>
            <Text style={styles.greeting}>Hello, {profile?.name?.split(' ')[0] || 'Customer'} 👋</Text>
            <Text style={styles.shopName}>Thanni CAN</Text>
          </View>
          <Pressable style={styles.profileBtn} onPress={() => navigation.navigate('Profile')}>
            <AppIcon name="person" size={20} color="#1E7A45" />
          </Pressable>
        </View>

        {/* Hero image */}
        <View style={styles.heroCard}>
          <Image source={waterCanImage} style={styles.heroImage} resizeMode="cover" />
          <View style={styles.heroOverlay}>
            <View style={styles.heroBadge}>
              <Text style={styles.heroBadgeText}>Fresh • Pure • Fast</Text>
            </View>
            <Text style={styles.heroTitle}>20L Drinking{'\n'}Water Can</Text>
          </View>
        </View>

        {/* Product details card */}
        <View style={styles.productCard}>
          <View style={styles.productRow}>
            <View style={styles.productInfo}>
              <Text style={styles.productName}>{WATER_PRODUCT.name}</Text>
              <Text style={styles.productSubtitle}>{WATER_PRODUCT.subtitle}</Text>
            </View>
            <View style={styles.priceBox}>
              <Text style={styles.priceValue}>{formatCurrency(WATER_PRODUCT.pricePerCan)}</Text>
              <Text style={styles.priceLabel}>per can</Text>
            </View>
          </View>

          <View style={styles.statsRow}>
            <View style={styles.statBox}>
              <AppIcon name="cube-outline" size={16} color="#1A7FD4" />
              <Text style={styles.statValue}>{liveStock}</Text>
              <Text style={styles.statLabel}>In stock</Text>
            </View>
            <View style={styles.statDivider} />
            <View style={styles.statBox}>
              <AppIcon name="time-outline" size={16} color="#1A7FD4" />
              <Text style={styles.statValue}>30 min</Text>
              <Text style={styles.statLabel}>Express</Text>
            </View>
            <View style={styles.statDivider} />
            <View style={styles.statBox}>
              <AppIcon name="receipt-outline" size={16} color="#1A7FD4" />
              <Text style={styles.statValue}>{orders.length}</Text>
              <Text style={styles.statLabel}>My orders</Text>
            </View>
          </View>

          {liveStock <= WATER_PRODUCT.lowStockThreshold ? (
            <View style={styles.lowStockBanner}>
              <AppIcon name="warning-outline" size={14} color="#B45309" />
              <Text style={styles.lowStockText}>Only {liveStock} cans left — order soon!</Text>
            </View>
          ) : null}
        </View>

        {/* Order card */}
        <View style={styles.orderCard}>
          <Text style={styles.orderCardTitle}>Place Order</Text>
          <View style={styles.qtyRow}>
            <Text style={styles.qtyLabel}>Quantity</Text>
            <View style={styles.qtyControls}>
              <Pressable style={styles.qtyBtn} onPress={() => setQuantity(q => Math.max(1, q - 1))}>
                <Text style={styles.qtyBtnText}>−</Text>
              </Pressable>
              <Text style={styles.qtyValue}>{quantity}</Text>
              <Pressable style={styles.qtyBtn} onPress={() => setQuantity(q => Math.min(liveStock, q + 1))}>
                <Text style={styles.qtyBtnText}>+</Text>
              </Pressable>
            </View>
          </View>
          <View style={styles.orderSummaryRow}>
            <Text style={styles.orderSummaryLabel}>Total</Text>
            <Text style={styles.orderSummaryValue}>{formatCurrency(quantity * WATER_PRODUCT.pricePerCan)}</Text>
          </View>
          <Pressable style={[styles.orderBtn, ordering && styles.orderBtnDisabled]} onPress={handleQuickOrder} disabled={ordering}>
            <AppIcon name="flash" size={20} color="#fff" />
            <Text style={styles.orderBtnText}>{ordering ? 'Placing Order...' : `Order ${quantity} Can${quantity > 1 ? 's' : ''} Now`}</Text>
          </Pressable>
        </View>

        {/* Recent orders */}
        {orders.length > 0 && (
          <View style={styles.recentBox}>
            <View style={styles.recentHeader}>
              <Text style={styles.recentTitle}>Recent Orders</Text>
              <Pressable onPress={() => navigation.navigate('CustomerOrders')}>
                <Text style={styles.recentSeeAll}>See all</Text>
              </Pressable>
            </View>
            {orders.slice(0, 3).map(order => (
              <View key={order.id} style={styles.recentItem}>
                <View style={[styles.recentDot, { backgroundColor: order.status === 'delivered' ? '#1E7A45' : order.status === 'cancelled' ? '#DC2626' : '#1A7FD4' }]} />
                <View style={{ flex: 1 }}>
                  <Text style={styles.recentOrderNum}>Order #{order.orderNumber} · {order.quantity} can{order.quantity > 1 ? 's' : ''}</Text>
                  <Text style={styles.recentOrderStatus}>{order.status.replace('_', ' ')}</Text>
                </View>
                <Text style={styles.recentOrderAmt}>{formatCurrency(order.totalAmount)}</Text>
              </View>
            ))}
          </View>
        )}

        {/* Quick command box */}
        <View style={styles.commandBox}>
          <Text style={styles.commandTitle}>Quick actions</Text>
          <View style={styles.commandGrid}>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('NewOrder', {})}>
              <View style={styles.commandIcon}>
                <AppIcon name="add-circle-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>New Order</Text>
            </Pressable>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('CustomerOrders')}>
              <View style={styles.commandIcon}>
                <AppIcon name="receipt-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>My Orders</Text>
            </Pressable>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('OrderTracking', {})}>
              <View style={styles.commandIcon}>
                <AppIcon name="navigate-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>Track</Text>
            </Pressable>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('CustomerWallet')}>
              <View style={styles.commandIcon}>
                <AppIcon name="wallet-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>Wallet</Text>
            </Pressable>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('CustomerSubscription')}>
              <View style={styles.commandIcon}>
                <AppIcon name="calendar-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>Plan</Text>
            </Pressable>
            <Pressable style={styles.commandItem} onPress={() => navigation.navigate('Profile')}>
              <View style={styles.commandIcon}>
                <AppIcon name="person-outline" size={22} color="#1A7FD4" />
              </View>
              <Text style={styles.commandLabel}>Profile</Text>
            </Pressable>
          </View>
        </View>

        {/* Review box */}
        <View style={styles.reviewBox}>
          <View style={styles.reviewHeader}>
            <AppIcon name="star" size={18} color="#F59E0B" />
            <Text style={styles.reviewTitle}>How was your last delivery?</Text>
          </View>
          <View style={styles.reviewUser}>
            <View style={styles.reviewAvatar}>
              <Text style={styles.reviewAvatarText}>{profile?.name?.charAt(0).toUpperCase() || 'U'}</Text>
            </View>
            <View>
              <Text style={styles.reviewName}>{profile?.name || 'Customer'}</Text>
              <Text style={styles.reviewSubtext}>
                {submittedRating > 0 ? `You rated us ${submittedRating} star${submittedRating > 1 ? 's' : ''}` : 'Tap a star to rate'}
              </Text>
            </View>
          </View>
          <View style={styles.starsRow}>
            {[1, 2, 3, 4, 5].map((star) => (
              <Pressable key={star} style={styles.starBtn} onPress={() => handleSubmitReview(star)} disabled={submitting}>
                <AppIcon
                  name={star <= selectedRating ? 'star' : 'star-outline'}
                  size={32}
                  color={star <= selectedRating ? '#F59E0B' : '#C8DFF5'}
                />
              </Pressable>
            ))}
          </View>
          {submittedRating > 0 ? (
            <View style={styles.reviewDone}>
              <AppIcon name="checkmark-circle" size={16} color="#1A7FD4" />
              <Text style={styles.reviewDoneText}>Rating saved. Thank you, {profile?.name?.split(' ')[0]}!</Text>
            </View>
          ) : (
            <Text style={styles.reviewHint}>Your feedback helps us deliver better.</Text>
          )}
        </View>

      </ScrollView>
      <CustomerBottomNav active="CustomerHome" />
    </SafeAreaView>
  );
};

